// --- types.d.ts ---
import { ReactNode } from 'react';

export interface ForecastDay {
  day: string;
  icon: string;
  high: number;
  low: number;
}

export interface WeatherCardProps {
  city: string;
  temperature: number;
  condition: string;
  humidity: number;
  windSpeed: number;
  unit?: 'C' | 'F';
  forecast: ForecastDay[];
}

export interface WeatherCardHookReturn {
  formattedTemp: string;
  unitLabel: string;
  conditionIcon: string;
  humidityDisplay: string;
  windDisplay: string;
  forecastData: ForecastDay[];
}

export interface CurrentWeatherProps {
  temperature: string;
  unit: string;
  condition: string;
  icon: string;
  city: string;
}

export interface WeatherMetricsProps {
  humidity: string;
  windSpeed: string;
}

export interface ForecastStripProps {
  forecast: ForecastDay[];
  unit: string;
}

export interface ForecastItemProps {
  data: ForecastDay;
  unit: string;
}


// --- constants.ts ---
// constants.ts — static data, mappings, configurations

/**
 * Mapping of common weather conditions to emoji icons.
 * Keys are normalized to lowercase for easier lookup.
 */
export const WEATHER_ICONS: Record<string, string> = {
  'sunny': '☀️',
  'clear': '☀️',
  'cloudy': '☁️',
  'partly cloudy': '⛅',
  'rainy': '🌧️',
  'showers': '🌦️',
  'thunderstorm': '⛈️',
  'snowy': '❄️',
  'windy': '💨',
  'foggy': '🌫️',
  'mist': '🌫️',
};

/**
 * Fallback icon when a condition is not found in the WEATHER_ICONS map.
 */
export const DEFAULT_ICON = '🌡️';

/**
 * Display labels for temperature units.
 */
export const UNIT_LABELS = {
  'C': '°C',
  'F': '°F',
} as const;

/**
 * UI labels for weather metrics.
 */
export const METRIC_LABELS = {
  HUMIDITY: 'Humidity',
  WIND_SPEED: 'Wind Speed',
} as const;

/**
 * The default unit used when none is provided.
 */
export const DEFAULT_UNIT = 'C';


// --- hooks.ts ---
import { useMemo } from 'react';
import type { WeatherCardProps, WeatherCardHookReturn } from './types';

export function useWeatherCard(props: WeatherCardProps): WeatherCardHookReturn {
  const { temperature, unit, condition, humidity, windSpeed, forecast } = props;

  return useMemo(() => {
    // Condition to Icon Mapping
    const conditionMap: Record<string, string> = {
      sunny: '☀️',
      cloudy: '☁️',
      rainy: '🌧️',
      snowy: '❄️',
      thunderstorm: '⛈️',
      partlyCloudy: '⛅',
    };

    const formattedTemp = `${Math.round(temperature)}°`;

    const unitLabel = unit === 'F' ? '°F' : '°C';

    const conditionIcon = conditionMap[condition.toLowerCase()] || '⛅';

    const humidityDisplay = `${humidity}%`;

    const speedUnit = unit === 'F' ? 'mph' : 'km/h';
    const windDisplay = `${windSpeed} ${speedUnit}`;

    return {
      formattedTemp,
      unitLabel,
      conditionIcon,
      humidityDisplay,
      windDisplay,
      forecastData: forecast,
    };
  }, [temperature, unit, condition, humidity, windSpeed, forecast]);
}


// --- components/CurrentWeather.tsx ---
import React from 'react';
import { Stack, Text, Heading } from '@ggui-ai/design/primitives';
import { CurrentWeatherProps } from '../types';

/**
 * CurrentWeather component displays the primary weather data for the selected location.
 * It features a large temperature display, the location name, and the current condition with an icon.
 */
export const CurrentWeather: React.FC<CurrentWeatherProps> = ({
  temperature,
  unit,
  condition,
  icon,
  city,
}) => {
  return (
    <Stack align="center" gap={8}>
      {/* Location Header */}
      <Text
        size="sm"
        weight="medium"
        color="var(--ggui-color-onSurfaceVariant, #52525b)"
      >
        {city}
      </Text>

      {/* Temperature Display */}
      <Heading
        level={1}
        color="var(--ggui-color-onSurface, #18181b)"
        style={{
          fontSize: 'var(--ggui-font-size-6xl, 3.75rem)',
          fontWeight: 'var(--ggui-font-weight-bold, 700)',
          display: 'flex',
          alignItems: 'flex-start',
          lineHeight: 1,
        }}
      >
        {temperature}
        <span
          style={{
            fontSize: 'var(--ggui-font-size-2xl, 1.5rem)',
            fontWeight: 'var(--ggui-font-weight-medium, 500)',
            marginTop: '0.25rem',
          }}
        >
          °{unit}
        </span>
      </Heading>

      {/* Weather Condition & Icon */}
      <Stack direction="horizontal" align="center" gap={8}>
        <span
          role="img"
          aria-label={condition}
          style={{
            fontSize: 'var(--ggui-font-size-3xl, 30px)',
            width: 'var(--ggui-spacing-8, 32px)',
            height: 'var(--ggui-spacing-8, 32px)',
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'center',
          }}
        >
          {icon}
        </span>
        <Text
          size="lg"
          color="var(--ggui-color-onSurfaceVariant, #52525b)"
        >
          {condition}
        </Text>
      </Stack>
    </Stack>
  );
};

export default CurrentWeather;


// --- components/WeatherMetrics.tsx ---
import React from 'react';
import { Stack, Text } from '@ggui-ai/design/primitives';
import { WeatherMetricsProps } from '../types';

export const WeatherMetrics: React.FC<WeatherMetricsProps> = ({ humidity, windSpeed }) => {
  return (
    <Stack 
      direction="horizontal" 
      justify="around" 
      gap={24}
      style={{ width: '100%' }}
    >
      {/* Humidity Metric */}
      <Stack direction="vertical" align="center" gap={4}>
        <Text 
          variant="overline" 
          color="var(--ggui-color-onSurfaceVariant, #52525b)"
        >
          HUMIDITY
        </Text>
        <Text 
          variant="bodyLarge" 
          weight="bold" 
          color="var(--ggui-color-onSurface, #18181b)"
        >
          {humidity}
        </Text>
      </Stack>

      {/* Wind Speed Metric */}
      <Stack direction="vertical" align="center" gap={4}>
        <Text 
          variant="overline" 
          color="var(--ggui-color-onSurfaceVariant, #52525b)"
        >
          WIND
        </Text>
        <Text 
          variant="bodyLarge" 
          weight="bold" 
          color="var(--ggui-color-onSurface, #18181b)"
        >
          {windSpeed}
        </Text>
      </Stack>
    </Stack>
  );
};


// --- components/ForecastStrip.tsx ---
import React from 'react';
import { Stack, Text } from '@ggui-ai/design/primitives';
import { ForecastStripProps, ForecastItemProps } from '../types';

/**
 * ForecastItem - A sub-component to render an individual day's forecast.
 */
const ForecastItem = ({ data, unit }: ForecastItemProps) => {
  const { day, icon, high, low } = data;

  return (
    <Stack align="center" gap={4}>
      <Text
        variant="caption"
        weight="semibold"
        color="var(--ggui-color-onSurfaceVariant, #52525b)"
      >
        {day.substring(0, 3).toUpperCase()}
      </Text>
      <Text size="2xl">
        {icon}
      </Text>
      <Stack direction="horizontal" gap={2} align="center">
        <Text
          variant="bodySmall"
          weight="bold"
          color="var(--ggui-color-onSurface, #18181b)"
        >
          {high}°{unit}
        </Text>
        <Text
          variant="bodySmall"
          color="var(--ggui-color-onSurfaceVariant, #52525b)"
        >
          / {low}°{unit}
        </Text>
      </Stack>
    </Stack>
  );
};

/**
 * ForecastStrip - Displays a 5-day weather forecast horizontal list.
 */
export const ForecastStrip = ({ forecast, unit }: ForecastStripProps) => {
  if (!forecast || forecast.length === 0) {
    return null;
  }

  return (
    <div
      style={{
        borderTop: '1px solid var(--ggui-color-outlineVariant, #e4e4e7)',
        paddingTop: 'var(--ggui-spacing-4, 16px)',
        width: '100%',
        overflowX: 'auto',
      }}
    >
      <Stack
        direction="horizontal"
        justify="between"
        align="center"
        gap="var(--ggui-spacing-4, 16px)"
      >
        {forecast.map((dayData, index) => (
          <ForecastItem 
            key={`${dayData.day}-${index}`} 
            data={dayData} 
            unit={unit} 
          />
        ))}
      </Stack>
    </div>
  );
};

export default ForecastStrip;


// --- ui.tsx ---
// ui.tsx — main visual layout, design system primitives
import React from 'react';
import { Container, Stack, Card } from '@ggui-ai/design/primitives';
import type { WeatherCardProps, WeatherCardHookReturn } from './types';
import { CurrentWeather, WeatherMetrics, ForecastStrip } from './components';

export function ComponentUI(props: WeatherCardProps & WeatherCardHookReturn) {
  const {
    city,
    condition,
    unitLabel,
    formattedTemp,
    conditionIcon,
    humidityDisplay,
    windDisplay,
    forecastData,
  } = props;

  return (
    <Container maxWidth="sm" padding={16} center>
      <Card shadow="md" padding={24}>
        <Stack gap={24} direction="vertical">
          {/* Current Weather Section */}
          <CurrentWeather
            city={city}
            temperature={formattedTemp}
            unit={unitLabel}
            condition={condition}
            icon={conditionIcon}
          />

          {/* Divider */}
          <div
            style={{
              height: '1px',
              background: 'var(--ggui-color-neutral-200, #e5e7eb)',
              width: '100%',
            }}
          />

          {/* Metrics Section */}
          <WeatherMetrics
            humidity={humidityDisplay}
            windSpeed={windDisplay}
          />

          {/* Forecast Section */}
          <ForecastStrip
            forecast={forecastData}
            unit={unitLabel}
          />
        </Stack>
      </Card>
    </Container>
  );
}


// --- render.tsx ---
// render.tsx — entry point
import React from 'react';
import type { Props } from './types';
import { useComponent } from './hooks';
import { ComponentUI } from './ui';

export default function Component(props: Props) {
  const state = useComponent(props);
  return <ComponentUI {...props} {...state} />;
}
